// internal/generate/integration_test.go
package generate

// White-box end-to-end integration suite (PRD §20.1 layer 3; decisions.md §8):
// drives the REAL CommitStaged against a REAL temp git repo + the REAL stub
// agent binary across all seven contract paths. It is `package generate` so it
// can name the package-private gitClient/runner interfaces (needed for the CAS
// test's headMover decorator) and compose the in-package stub helpers
// (BuildStubBinary/NewStubManifest). stdlib + internal/{config,git,provider,ui} only.

import (
	"bytes"
	"context"
	"errors"
	"os/exec"
	"path/filepath"
	"strings"
	"testing"
	"time"

	"github.com/dustin/stagehand/internal/config"
	"github.com/dustin/stagehand/internal/git"
	"github.com/dustin/stagehand/internal/provider"
	"github.com/dustin/stagehand/internal/ui"
)

// gitRun is the raw-git fail-fast helper for repo BOOTSTRAP only (init/identity/
// write-file/stage/seed-history). Production plumbing goes through the REAL
// *git.Git wired into Deps.Git — this helper only does what *git.Git does not
// expose (init/add <file>/commit). It mirrors internal/git/gittestutil_test.go
// exactly: cmd.Dir=dir, exec.Command("git", args...), CombinedOutput, t.Fatalf.
func gitRun(t *testing.T, dir string, args ...string) string {
	t.Helper()
	cmd := exec.Command("git", args...)
	cmd.Dir = dir
	var stdout, stderr bytes.Buffer
	cmd.Stdout = &stdout
	cmd.Stderr = &stderr
	if err := cmd.Run(); err != nil {
		t.Fatalf("git %s: %v\nstderr: %s", strings.Join(args, " "), err, stderr.String())
	}
	return stdout.String()
}

// newTempRepo bootstraps an isolated, UNBORN repo with deterministic identity +
// repo-local gpgsign=false (mirrors internal/git/gittestutil_test.go). Returns
// the dir (bind a *git.Git to it via git.New for Deps.Git).
func newTempRepo(t *testing.T) string {
	t.Helper()
	dir := t.TempDir()
	gitRun(t, dir, "init", "-q")
	gitRun(t, dir, "config", "user.email", "stagehand@example.com")
	gitRun(t, dir, "config", "user.name", "Stagehand Test")
	gitRun(t, dir, "config", "commit.gpgsign", "false")
	return dir
}

// writeStage writes a file under the repo (creating parent dirs) and stages it
// via the REAL `git add` (path relative to dir). Mirrors writeFileStage.
func writeStage(t *testing.T, dir, path, content string) {
	t.Helper()
	// os.WriteFile to filepath.Join(dir, path) after MkdirAll(filepath.Dir), then gitRun add.
}

// seedCommit appends ONE linear commit (a unique file + `git commit -m msg`).
// The ENTIRE message (incl. newlines) is ONE -m arg. Mirrors seedCommits.
func seedCommit(t *testing.T, dir, msg string) {
	t.Helper()
	// writeStage a unique fileN.txt, then gitRun commit -q -m <msg>.
}

// headMoverRunner wraps the real *provider.Executor and, on the FIRST Run,
// advances HEAD via plumbing on HEAD^{tree} (so the staged INDEX is UNTOUCHED),
// making the parentSHA CommitStaged captured before the loop STALE ⇒ real CAS
// failure. It implements the package-private `runner` interface (Run+Parse).
type headMoverRunner struct {
	inner runner
	dir   string
	moved bool
}

func (r *headMoverRunner) Run(ctx context.Context, m provider.Manifest, model, prov, sys, payload string) (string, error) {
	if !r.moved {
		r.moved = true
		// Advance HEAD WITHOUT touching the index: build a new commit whose tree
		// is the CURRENT HEAD's tree (NOT the index), then update-ref HEAD.
		tree := strings.TrimSpace(gitRunTest(r.dir, "rev-parse", "HEAD^{tree}"))
		parent := strings.TrimSpace(gitRunTest(r.dir, "rev-parse", "HEAD"))
		newc := strings.TrimSpace(gitRunTest(r.dir, "commit-tree", "-p", parent, "-m", "concurrent commit elsewhere", tree))
		gitRunTest(r.dir, "update-ref", "HEAD", newc)
	}
	return r.inner.Run(ctx, m, model, prov, sys, payload)
}
func (r *headMoverRunner) Parse(raw string, m provider.Manifest) (string, bool) { return r.inner.Parse(raw, m) }
// (gitRunTest is gitRun parameterized on testing.TB so the decorator can call it; fold into gitRun.)

// e2eDeps builds a Deps wired to REAL *git.Git + REAL *provider.Executor + a
// stub Manifest, with overrideable config. Caller owns stdout/stderr buffers.
func e2eDeps(t *testing.T, dir string, script []StubResponse, cfg config.Config, stdout, stderr *bytes.Buffer) Deps {
	t.Helper()
	manifest := NewStubManifest(t, StubConfig{
		Script:    script,
		StateFile: filepath.Join(t.TempDir(), "c"), // required for multi-entry scripts
	})
	g, err := git.New(dir)
	if err != nil {
		t.Fatalf("git.New: %v", err)
	}
	return Deps{
		Git: g, Runner: provider.NewExecutor(""), Manifest: manifest,
		Config: cfg, Output: ui.NewOutput(stdout, stderr, false, true),
	}
}
```

### The 7 contract paths → exact stub script + assertions
```yaml
Test 1 — TestIntegration_Success:
  REPO: newTempRepo; seedCommit("feat: baseline"); writeStage("feature.go","package x\n").
  SCRIPT: [{Emit:"feat: add feature module\n\nImplements the new feature."}].
  EXPECT: nil err; Result non-empty.
  ASSERT (real git):
    - gitRun("cat-file","-t",res.CommitSHA) == "commit".
    - parse ^tree <hash>$ from gitRun("cat-file","-p",res.CommitSHA) == TrimSpace(gitRun("write-tree")).
    - parse ^parent <hash>$ == oldHead (captured pre-run).
    - TrimSpace(gitRun("log","-1","--format=%B",res.CommitSHA)) == res.Message.
    - stdout contains [<res.CommitSHA[:7]>] feat: add feature module.
    - stderr has NO rescue block.

Test 2 — TestIntegration_DupRetryThenSuccess:
  REPO: seedCommit("feat: dup"); writeStage("feature.go","package x\n").
  SCRIPT: [{Emit:"feat: dup"},{Emit:"feat: unique module"}].
  EXPECT: nil err; Result.Subject == "feat: unique module".
  ASSERT: commit message (%B) == the unique subject; HEAD advanced by exactly one commit.

Test 3 — TestIntegration_ParseFailThenRescue:
  REPO: writeStage("feature.go","package x\n") (history optional).
  SCRIPT: [{Emit:""},{Emit:""}]  # EMPTY — Decision D; non-empty would parse ok=true and commit.
  EXPECT: errors.Is(err, ErrRescue).
  ASSERT: rescue block in stderr (Commit generation failed / Tree ID:); NO commit created
    (HEAD rev unchanged; gitRun("cat-file","-t",<nothing>) — there is no returned SHA); HEAD + index
    unchanged (rev-parse + diff --cached --name-only before==after).

Test 4 — TestIntegration_Timeout:
  REPO: writeStage("feature.go","package x\n").
  SCRIPT: [{Hang:true}]; cfg.Timeout = 500*time.Millisecond.
  EXPECT: errors.Is(err, ErrRescue) (executor returns *provider.TimeoutError, NOT context.Canceled,
    so CommitStaged renders Rescue + returns ErrRescue).
  ASSERT: rescue in stderr; NO commit; HEAD + index unchanged.

Test 5 — TestIntegration_HeadMovedCASFailure:
  REPO: seedCommit("feat: baseline"); writeStage("feature.go","package x\n").
  RUNNER: headMoverRunner{inner: provider.NewExecutor(""), dir: dir} (wired in place of the bare
    executor in e2eDeps — or construct Deps inline for this test).
  SCRIPT: [{Emit:"feat: ok message"}].
  EXPECT: errors.Is(err, ErrHeadMoved).
  ASSERT:
    - stderr contains the §13.5 message ("HEAD moved", "aborting to avoid a non-fast-forward",
      "Your generated message was:", "git commit-tree", "xargs git update-ref HEAD").
    - stderr does NOT contain the rescue block (head-moved prints its own message; never rescues).
    - HEAD after == the decorator's concurrent commit (NOT the stagehand commit; NEVER forced).
    - index unchanged (the decorator used HEAD^{tree}, not the index).
    - (optional) the stagehand commit object is dangling/unreachable from any ref.

Test 6 — TestIntegration_RootCommit:
  REPO: newTempRepo (UNBORN — seed nothing); writeStage("README.md","hello\n").
  SCRIPT: [{Emit:"feat: initial commit"}].
  EXPECT: nil err.
  ASSERT: gitRun("cat-file","-p",res.CommitSHA) has NO ^parent line; tree line == write-tree;
    gitRun("rev-parse","HEAD") now succeeds and == res.CommitSHA (advanced from unborn).

Test 7 — TestIntegration_NothingStaged:
  REPO: newTempRepo; seedCommit("feat: baseline"); DO NOT stage anything (clean index).
  SCRIPT: [{Emit:"ignored"}] (never reached).
  EXPECT: errors.Is(err, ErrNothingToCommit).
  ASSERT: no rescue in stderr; HEAD + index unchanged; NO dangling tree created (WriteTree not
    reached — empty diff short-circuits before snapshot; this is the v2 seam: generate never stages).
```

